import json
import os
from pathlib import Path

session_dir = "/home/mega/.codex/sessions/2026/03/20"
summary = {}

for fname in sorted(os.listdir(session_dir)):
    if not fname.endswith('.jsonl'):
        continue
    fpath = os.path.join(session_dir, fname)

    messages = []
    record_types = {}

    try:
        with open(fpath, 'r') as f:
            for line in f:
                try:
                    record = json.loads(line.strip())
                    rtype = record.get('type', 'unknown')
                    record_types[rtype] = record_types.get(rtype, 0) + 1

                    # Extract content based on record type
                    if rtype == 'response_item':
                        payload = record.get('payload', {})
                        if 'content' in payload:
                            content = payload['content']
                            if isinstance(content, list):
                                # Join list items
                                msg = ' '.join(str(item) if not isinstance(item, dict) else str(item.get('text', '')) for item in content)
                            else:
                                msg = str(content)
                            messages.append(f"[response] {msg[:120]}")
                    elif rtype == 'event_msg':
                        payload = record.get('payload', {})
                        if 'message' in payload:
                            msg = str(payload['message'])[:120]
                            messages.append(f"[event] {msg}")
                    elif rtype == 'turn_context':
                        payload = record.get('payload', {})
                        if 'turn_id' in payload:
                            messages.append(f"[turn] {payload.get('turn_id', 'unknown')}")
                except Exception as e:
                    pass

        summary[fname] = {
            'record_types': record_types,
            'message_count': len(messages),
            'sample_messages': messages[:3]
        }
    except Exception as e:
        summary[fname] = {'error': str(e)}

# Print summary
for fname in sorted(summary.keys()):
    print(f"\n{fname}:")
    info = summary[fname]
    if 'error' in info:
        print(f"  Error: {info['error']}")
    else:
        print(f"  Record types: {info['record_types']}")
        print(f"  Total messages extracted: {info['message_count']}")
        if info['sample_messages']:
            print(f"  Sample content:")
            for msg in info['sample_messages']:
                print(f"    - {msg}")
